    var $categoryWrapper = $jq("#preferences-container");

    if (!$categoryWrapper.length || !$headerElement.length) {
        return;
    }

    const defaultCategories = [
        "Big Data",
        "Cloud",
        "Converged Infrastructure",
        "Data Protection",
        "Desktop",
        "Networking",
        "Security",
        "Servers",
        "Storage",
        "Systems Management"
    ];

    const email = $headerElement[0].dataset.eid || "";
    const language = $headerElement[0].dataset.language || "English";
    const country = $headerElement[0].dataset.location || "";

    const headerCategoriesRaw = $headerElement[0].dataset.category;

